function formatContrastRatio(foregroundHex: string, backgroundHex: string): string {
  const ratio = getContrastRatio(foregroundHex, backgroundHex);
  return `${ratio.toFixed(2)}:1`;
}

function getContrastRatio(foregroundHex: string, backgroundHex: string): number {
  const foregroundLuminance = getRelativeLuminance(foregroundHex);
  const backgroundLuminance = getRelativeLuminance(backgroundHex);
  const lighter = Math.max(foregroundLuminance, backgroundLuminance);
  const darker = Math.min(foregroundLuminance, backgroundLuminance);

  return (lighter + 0.05) / (darker + 0.05);
}

function getRelativeLuminance(hex: string): number {
  const [red, green, blue] = hexToRgb(hex).map((channel) => {
    const value = channel / 255;
    return value <= 0.03928 ? value / 12.92 : ((value + 0.055) / 1.055) ** 2.4;
  });

  return 0.2126 * red + 0.7152 * green + 0.0722 * blue;
}

function hexToRgb(hex: string): [number, number, number] {
  const normalized = hex.replace('#', '');
  const value = normalized.length === 3 ? normalized.replace(/(.)/g, '$1$1') : normalized;

  return [
    Number.parseInt(value.slice(0, 2), 16),
    Number.parseInt(value.slice(2, 4), 16),
    Number.parseInt(value.slice(4, 6), 16),
  ];
}

function toInlineStyle(values: Record<string, string>): string {
  return Object.entries(values)
    .map(([key, value]) => `${key}: ${value}`)
    .join('; ');
}

import {
  AfterViewChecked,
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  forwardRef,
  input,
  output,
  signal,
  viewChild,
} from '@angular/core';
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';

export interface MnlSelectOption {
  readonly value: string;
  readonly label: string;
  readonly disabled?: boolean;
}

export type MnlSelectValue = string | null;

const containerBaseClasses =
  'flex min-h-11 w-full items-center gap-3 rounded-lg border bg-mnl-surface px-3 shadow-sm transition-[border-color,box-shadow,background-color] duration-200 motion-reduce:transition-none';
const containerDefaultClasses =
  'border-mnl-border text-mnl-text focus-within:border-mnl-pink focus-within:ring-2 focus-within:ring-mnl-pink';
const containerErrorClasses =
  'border-mnl-red text-mnl-text ring-2 ring-mnl-red focus-within:border-mnl-red focus-within:ring-mnl-red';
const containerDisabledClasses =
  'pointer-events-none cursor-not-allowed bg-mnl-surface-alt text-mnl-subtext opacity-60 shadow-none';
const selectClasses =
  'form-select w-full min-w-0 appearance-none border-0 bg-transparent px-0 py-0 pr-7 text-sm text-inherit shadow-none ring-0 outline-hidden focus:border-0 focus:ring-0 disabled:cursor-not-allowed disabled:text-mnl-subtext';

@Component({
  selector: 'mnl-select',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => MnlSelectComponent),
      multi: true,
    },
  ],
  host: {
    class: 'block w-full',
  },
  template: `
    <label
      [attr.aria-disabled]="isDisabled() ? 'true' : null"
      [attr.data-has-error]="hasError()"
      [class]="containerClasses()"
      data-testid="mnl-select-field"
    >
      <span
        aria-hidden="true"
        class="inline-flex shrink-0 items-center justify-center text-mnl-subtext empty:hidden"
      >
        <ng-content select="[mnlSelectLeadingIcon]"></ng-content>
      </span>

      <div class="relative min-w-0 flex-1">
        <select
          #selectElement
          [attr.aria-invalid]="hasError() ? 'true' : null"
          [attr.id]="id() || null"
          [attr.name]="name() || null"
          [class]="controlClasses()"
          [disabled]="isDisabled()"
          [value]="displayValue()"
          data-testid="mnl-select"
          (blur)="handleBlur()"
          (change)="handleChange($event)"
        >
          @if (placeholder()) {
            <option value="">{{ placeholder() }}</option>
          }

          @for (option of options(); track option.value) {
            <option [disabled]="option.disabled ?? false" [value]="option.value">
              {{ option.label }}
            </option>
          }

          <ng-content select="option,optgroup"></ng-content>
        </select>

        <span
          aria-hidden="true"
          class="pointer-events-none absolute inset-y-0 right-0 inline-flex items-center justify-center text-mnl-subtext"
        >
          <svg
            class="size-4"
            fill="none"
            stroke="currentColor"
            stroke-linecap="round"
            stroke-linejoin="round"
            stroke-width="1.75"
            viewBox="0 0 24 24"
          >
            <path d="m6 9 6 6 6-6" />
          </svg>
        </span>
      </div>
    </label>
  `,
})
export class MnlSelectComponent implements AfterViewChecked, ControlValueAccessor {
  readonly disabled = input(false);
  readonly error = input<boolean | string | null>(null);
  readonly id = input('');
  readonly name = input('');
  readonly options = input<readonly MnlSelectOption[]>([]);
  readonly placeholder = input('');

  readonly valueChange = output<MnlSelectValue>();

  private readonly selectElement = viewChild<ElementRef<HTMLSelectElement>>('selectElement');
  private readonly cvaDisabled = signal(false);
  private readonly currentValue = signal<MnlSelectValue>('');
  private onChange: (value: MnlSelectValue) => void = () => undefined;
  private onTouched: () => void = () => undefined;

  protected readonly hasError = computed(() => Boolean(this.error()));
  protected readonly isDisabled = computed(() => this.disabled() || this.cvaDisabled());
  protected readonly containerClasses = computed(() =>
    [
      containerBaseClasses,
      this.hasError() ? containerErrorClasses : containerDefaultClasses,
      this.isDisabled() ? containerDisabledClasses : '',
    ]
      .filter(Boolean)
      .join(' '),
  );
  protected readonly controlClasses = computed(() => selectClasses);
  protected readonly displayValue = computed(() => this.currentValue() ?? '');

  writeValue(value: MnlSelectValue): void {
    this.currentValue.set(this.normalizeValue(value));
  }

  registerOnChange(fn: (value: MnlSelectValue) => void): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }

  setDisabledState(isDisabled: boolean): void {
    this.cvaDisabled.set(isDisabled);
  }

  ngAfterViewChecked(): void {
    const select = this.selectElement();
    if (select) {
      const value = this.displayValue();
      if (select.nativeElement.value !== value) {
        select.nativeElement.value = value;
      }
    }
  }

  protected handleBlur(): void {
    this.onTouched();
  }

  protected handleChange(event: Event): void {
    if (this.isDisabled()) {
      return;
    }

    const nextValue = this.readValue(event);
    this.currentValue.set(nextValue);
    this.onChange(nextValue);
    this.valueChange.emit(nextValue);
  }

  private normalizeValue(value: MnlSelectValue): MnlSelectValue {
    return value === '' || value == null ? '' : value;
  }

  private readValue(event: Event): MnlSelectValue {
    const element = event.target as HTMLSelectElement;
    return element.value === '' ? null : element.value;
  }
}

import { ChangeDetectionStrategy, Component, inject, input } from '@angular/core';
import { toSignal } from '@angular/core/rxjs-interop';
import { IsActiveMatchOptions, NavigationEnd, Router, RouterLink } from '@angular/router';
import {
  Bell,
  Calendar,
  House,
  Landmark,
  ListTodo,
  LucideAngularModule,
  PiggyBank,
  Settings,
  TrendingUp,
  User,
  Wallet,
} from 'lucide-angular';
import { filter, map, startWith } from 'rxjs';

export interface MnlTabBarItem {
  readonly icon: string;
  readonly label: string;
  readonly route: string;
  readonly badge?: number;
}

const iconMap = {
  Bell,
  Calendar,
  House,
  Landmark,
  ListTodo,
  PiggyBank,
  Settings,
  TrendingUp,
  User,
  Wallet,
} as const;

const mobileLinkBaseClasses =
  'relative inline-flex min-h-14 min-w-0 flex-1 flex-col items-center justify-center gap-1 rounded-2xl px-3 py-2 text-xs font-semibold text-mnl-subtext transition-colors duration-200 hover:bg-mnl-surface-alt hover:text-mnl-text focus-visible:outline-hidden focus-visible:ring-2 focus-visible:ring-mnl-accent focus-visible:ring-offset-2 focus-visible:ring-offset-mnl-bg motion-reduce:transition-none';
const mobileLinkActiveClasses =
  'bg-mnl-accent text-mnl-mocha-crust shadow-sm ring-1 ring-mnl-accent-strong/40';
const desktopLinkBaseClasses =
  'group inline-flex w-full items-center gap-3 rounded-2xl px-4 py-3 text-sm font-semibold text-mnl-subtext transition-colors duration-200 hover:bg-mnl-surface-alt hover:text-mnl-text focus-visible:outline-hidden focus-visible:ring-2 focus-visible:ring-mnl-accent focus-visible:ring-offset-2 focus-visible:ring-offset-mnl-bg motion-reduce:transition-none';
const desktopLinkActiveClasses =
  'bg-mnl-accent text-mnl-mocha-crust shadow-sm ring-1 ring-mnl-accent-strong/40';

@Component({
  selector: 'mnl-tab-bar',
  standalone: true,
  imports: [LucideAngularModule, RouterLink],
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    class: 'contents',
  },
  template: `
    <nav
      aria-label="Primary navigation"
      class="fixed inset-x-4 bottom-4 z-30 lg:hidden"
      data-layout="mobile"
      data-testid="mnl-tab-bar-mobile"
    >
      <div
        class="flex items-center gap-2 rounded-[1.75rem] border border-mnl-border/80 bg-mnl-surface/95 p-2 shadow-lg shadow-black/5 backdrop-blur supports-[backdrop-filter]:bg-mnl-surface/90"
      >
        @for (item of items(); track item.route) {
          <a
            [attr.aria-current]="isRouteActive(item.route) ? 'page' : null"
            [attr.data-active]="isRouteActive(item.route) ? 'true' : 'false'"
            [attr.data-route]="item.route"
            [attr.data-testid]="'mnl-tab-bar-mobile-item-' + item.route"
            [class]="mobileLinkClasses(item.route)"
            [routerLink]="item.route"
          >
            <span class="relative inline-flex">
              <lucide-icon
                [img]="resolveIcon(item.icon)"
                aria-hidden="true"
                class="size-5"
                data-testid="mnl-tab-bar-icon"
              ></lucide-icon>

              @if (item.badge != null) {
                <span
                  class="absolute -top-2 -right-2 inline-flex min-h-5 min-w-5 items-center justify-center rounded-full bg-mnl-error px-1 text-[0.65rem] font-bold leading-none text-mnl-mocha-crust"
                  data-testid="mnl-tab-bar-badge"
                >
                  {{ item.badge }}
                </span>
              }
            </span>

            <span class="truncate">{{ item.label }}</span>
          </a>
        }
      </div>
    </nav>

    <nav
      aria-label="Primary navigation"
      class="hidden h-dvh w-72 shrink-0 lg:flex"
      data-layout="desktop"
      data-testid="mnl-tab-bar-desktop"
    >
      <div class="flex w-full flex-col border-r border-mnl-border bg-mnl-surface/90 px-4 py-6">
        <div class="px-2">
          <p class="m-0 text-xs font-semibold uppercase tracking-[0.24em] text-mnl-accent">Menlo</p>
          <h2 class="mt-3 mb-0 text-2xl font-bold tracking-tight text-mnl-text">Household hub</h2>
          <p class="mt-2 mb-0 text-sm leading-6 text-mnl-subtext">
            Navigation adapts between a thumb-friendly tab bar and spacious desktop sidebar.
          </p>
        </div>

        <div class="mt-8 flex flex-1 flex-col gap-2">
          @for (item of items(); track item.route) {
            <a
              [attr.aria-current]="isRouteActive(item.route) ? 'page' : null"
              [attr.data-active]="isRouteActive(item.route) ? 'true' : 'false'"
              [attr.data-route]="item.route"
              [attr.data-testid]="'mnl-tab-bar-desktop-item-' + item.route"
              [class]="desktopLinkClasses(item.route)"
              [routerLink]="item.route"
            >
              <span
                class="inline-flex size-11 shrink-0 items-center justify-center rounded-2xl bg-mnl-surface-alt text-inherit ring-1 ring-mnl-border/70 transition-colors duration-200 motion-reduce:transition-none group-hover:bg-mnl-bg"
              >
                <lucide-icon
                  [img]="resolveIcon(item.icon)"
                  aria-hidden="true"
                  class="size-5"
                  data-testid="mnl-tab-bar-icon"
                ></lucide-icon>
              </span>

              <span class="min-w-0 flex-1 truncate">{{ item.label }}</span>

              @if (item.badge != null) {
                <span
                  class="inline-flex min-h-6 min-w-6 items-center justify-center rounded-full bg-mnl-error px-2 text-xs font-bold leading-none text-mnl-mocha-crust"
                  data-testid="mnl-tab-bar-badge"
                >
                  {{ item.badge }}
                </span>
              }
            </a>
          }
        </div>
      </div>
    </nav>
  `,
})
export class MnlTabBarComponent {
  readonly items = input.required<readonly MnlTabBarItem[]>();

  private readonly router = inject(Router);
  private readonly currentUrl = toSignal(
    this.router.events.pipe(
      filter((event): event is NavigationEnd => event instanceof NavigationEnd),
      map(() => this.router.url),
      startWith(this.router.url),
    ),
    { initialValue: this.router.url },
  );

  private readonly exactRouteOptions: IsActiveMatchOptions = {
    paths: 'exact',
    queryParams: 'ignored',
    fragment: 'ignored',
    matrixParams: 'ignored',
  };

  private readonly nestedRouteOptions: IsActiveMatchOptions = {
    paths: 'subset',
    queryParams: 'ignored',
    fragment: 'ignored',
    matrixParams: 'ignored',
  };

  protected resolveIcon(icon: string) {
    return iconMap[icon as keyof typeof iconMap] ?? House;
  }

  protected desktopLinkClasses(route: string): string {
    return this.isRouteActive(route)
      ? `${desktopLinkBaseClasses} ${desktopLinkActiveClasses}`
      : desktopLinkBaseClasses;
  }

  protected isRouteActive(route: string): boolean {
    this.currentUrl();
    return this.router.isActive(route, this.routeMatchOptions(route));
  }

  protected mobileLinkClasses(route: string): string {
    return this.isRouteActive(route)
      ? `${mobileLinkBaseClasses} ${mobileLinkActiveClasses}`
      : mobileLinkBaseClasses;
  }

  protected routeMatchOptions(route: string): IsActiveMatchOptions {
    return route === '/' ? this.exactRouteOptions : this.nestedRouteOptions;
  }
}

